# Get hardware hash for consistent comparisons
.get_hardware_hash <- function() {
  info <- Sys.info()
  # Create a simple hash from system info
  hardware_string <- paste(
    info["sysname"],
    info["machine"],
    info["nodename"],
    sep = "_"
  )
  digest::digest(hardware_string, algo = "xxhash32")
}

# Save benchmark results to parquet database
.save_benchmark_results <- function(results_df, output_dir) {
  db_path <- fs::path(output_dir, "perf.parquet")

  # Use the new sv_perf_add function which handles schema properly
  tryCatch({
    sv_perf_add(results_df, db_path = db_path)
  }, error = function(e) {
    cli::cli_warn(
      c("Failed to save benchmark results to database",
        "i" = "Error: {e$message}")
    )
  })
}

# Print benchmark summary
.print_bench_summary <- function(results_df) {
  cli::cli_rule("Benchmark Summary")

  # Group by spec and language
  for (spec in unique(results_df$spec_id)) {
    cli::cli_h3(spec)
    spec_results <- results_df[results_df$spec_id == spec, ]

    for (i in seq_len(nrow(spec_results))) {
      row <- spec_results[i, ]
      cli::cli_alert_info(
        "{row$language}: {.val {format(row$median * 1e6, digits = 2)}\u00b5s} median ({row$n_itr} iterations)"
      )
    }
  }
}

#' Scaffold Test Files for Target Language
#'
#' Generates idiomatic test harnesses in the target language based on existing
#' spec files. Creates native test files that load specs and write cache results.
#'
#' @param lang Target language ("R", "python", "rust")
#' @param spec_dir Directory containing spec files (default: "spec")
#' @param test_dir Directory to write test files (default: "tests")
#' @param verify_functions Logical, whether to verify target functions exist
#' @param include_benchmarks Logical, whether to include benchmark tests (default: FALSE)
#'
#' @return Paths to created test files (invisibly)
#' @export
#'
#' @examples
#' \dontrun{
#' # Scaffold Python tests
#' sv_scaffold("python")
#' 
#' # Scaffold R tests with verification
#' sv_scaffold("R", verify_functions = TRUE)
#' 
#' # Scaffold R tests with benchmarks
#' sv_scaffold("R", include_benchmarks = TRUE)
#' }
sv_scaffold <- function(lang, spec_dir = "spec", test_dir = "tests", 
                        verify_functions = FALSE, include_benchmarks = FALSE) {

  lang <- tolower(lang)
  supported_langs <- c("r", "python", "rust")

  if (!lang %in% supported_langs) {
    cli::cli_abort("Unsupported language: {lang}. Supported: {paste(supported_langs, collapse = ', ')}")
  }

  if (!fs::dir_exists(spec_dir)) {
    cli::cli_abort("Spec directory does not exist: {spec_dir}")
  }

  # Get spec files
  spec_files <- fs::dir_ls(spec_dir, glob = "*.json")

  if (length(spec_files) == 0) {
    cli::cli_warn("No spec files found in {spec_dir}")
    return(invisible(character(0)))
  }

  # Create target test directory
  lang_test_dir <- switch(lang,
    "r" = fs::path(test_dir, "testthat"),
    "python" = fs::path(test_dir, "pytest"),
    "rust" = fs::path(test_dir, "rust")
  )

  if (!fs::dir_exists(lang_test_dir)) {
    fs::dir_create(lang_test_dir, recurse = TRUE)
    cli::cli_inform("Created test directory: {lang_test_dir}")
  }

  # Process each spec file
  created_files <- character(0)

  for (spec_file in spec_files) {
    spec_data <- jsonlite::read_json(spec_file)
    spec_name <- spec_data$name

    if (verify_functions) {
      .verify_function_exists(spec_data, lang)
    }

    test_file <- switch(lang,
      "r" = .create_r_test(spec_data, lang_test_dir, include_benchmarks),
      "python" = .create_python_test(spec_data, lang_test_dir, include_benchmarks),
      "rust" = .create_rust_test(spec_data, lang_test_dir, include_benchmarks)
    )

    created_files <- c(created_files, test_file)
    cli::cli_inform("Created {lang} test: {test_file}")
  }

  # Create helper files if needed
  if (lang == "python") {
    .create_python_helper(lang_test_dir)
  } else if (lang == "rust") {
    .create_rust_helper(lang_test_dir)
  }

  invisible(created_files)
}

# Verify that target function exists (T-09)
.verify_function_exists <- function(spec_data, lang) {
  func_name <- spec_data$function_name

  if (lang == "r") {
    # Try to find function in global environment or attached packages
    if (!exists(func_name, mode = "function")) {
      cli::cli_warn("Function '{func_name}' not found in R environment")
    }
  } else if (lang == "python") {
    # This would require more complex verification - skip for now
    # Could use reticulate to check if function exists in Python module
    cli::cli_inform("Python function verification not implemented yet")
  }
}

# Create R testthat test file
.create_r_test <- function(spec_data, test_dir, include_benchmarks = FALSE) {
  spec_name <- spec_data$name
  func_name <- spec_data$function_name

  test_content <- glue::glue('
test_that("{spec_name} produces expected output", {{
  # Load spec
  spec_file <- here::here("spec", "{spec_name}.v1.json")
  spec_data <- jsonlite::read_json(spec_file)

  # Execute function with spec inputs
  result <- do.call({func_name}, spec_data$inputs)

  # Compare with expected output
  expect_equal(result, spec_data$output, tolerance = 1e-12)

  # Write cache result
  run_id <- digest::digest(Sys.time())
  cache_dir <- here::here("results", "cache", run_id)
  if (!fs::dir_exists(cache_dir)) fs::dir_create(cache_dir, recurse = TRUE)

  cache_data <- list(
    spec_name = "{spec_name}",
    language = "R",
    output = result,
    timestamp = Sys.time()
  )

  cache_file <- fs::path(cache_dir, "{spec_name}.R.json")
  jsonlite::write_json(cache_data, cache_file, auto_unbox = TRUE, pretty = TRUE)
}})
', .trim = TRUE)

  # Add benchmark test if requested
  if (include_benchmarks) {
    bench_content <- glue::glue('

test_that("{spec_name} benchmark performance", {{
  skip_if_not_installed("bench")

  # Load spec
  spec_file <- here::here("spec", "{spec_name}.v1.json")
  spec_data <- jsonlite::read_json(spec_file)

  # Run benchmark
  bench_result <- bench::mark(
    do.call({func_name}, spec_data$inputs),
    min_iterations = 10,
    max_time = 5,
    check = FALSE
  )

  # Basic performance assertion (can be customized)
  expect_true(bench_result$median[1] < 1) # Expect < 1 second median time

  # Optional: Save benchmark results for tracking
  # This integrates with sv_bench() database
  if (requireNamespace("specverse", quietly = TRUE)) {{
    bench_df <- data.frame(
      spec_id = "{spec_name}",
      language = "R",
      timestamp = Sys.time(),
      min = as.numeric(bench_result$min[1]),
      median = as.numeric(bench_result$median[1]),
      max = max(as.numeric(bench_result$time[[1]])),
      itr_per_sec = bench_result$`itr/sec`[1],
      n_itr = bench_result$n_itr[1],
      memory = as.numeric(bench_result$mem_alloc[1]),
      hardware_hash = specverse:::.get_hardware_hash(),
      stringsAsFactors = FALSE
    )

    # Save to performance database if available
    tryCatch({{
      specverse::sv_perf_add(bench_df)
    }}, error = function(e) {{
      message("Could not save benchmark to database: ", e$message)
    }})
  }}
}})
', .trim = TRUE)

    test_content <- paste0(test_content, bench_content)
  }

  test_file <- fs::path(test_dir, paste0("test-", spec_name, ".R"))
  writeLines(test_content, test_file)

  return(test_file)
}

