#' Run Performance Benchmarks
#'
#' Executes performance benchmarks for functions defined in spec files and
#' stores results in a parquet database for tracking performance over time.
#'
#' @param spec_dir Directory containing spec files (default: "spec")
#' @param output_dir Directory for performance database (default: "results")
#' @param languages Character vector of languages to benchmark (default: c("R", "python"))
#' @param max_time Maximum time in seconds for each benchmark (default: 5)
#' @param min_iterations Minimum iterations for reliable benchmarks (default: 3)
#' @param verbose Logical, whether to print progress messages
#'
#' @return A data frame with benchmark results
#' @export
#'
#' @examples
#' \dontrun{
#' # Run benchmarks for all specs
#' results <- sv_bench()
#' 
#' # Run benchmarks with custom settings
#' results <- sv_bench(languages = c("R", "python", "rust"), max_time = 10)
#' }
sv_bench <- function(spec_dir = "spec", 
                     output_dir = "results",
                     languages = c("R", "python"),
                     max_time = 5,
                     min_iterations = 3,
                     verbose = TRUE) {

  # Check for bench package
  if (!requireNamespace("bench", quietly = TRUE)) {
    cli::cli_abort(
      c("Package {.pkg bench} is required for benchmarking",
        "i" = "Install it with: install.packages('bench')")
    )
  }

  # Validate directories
  if (!fs::dir_exists(spec_dir)) {
    cli::cli_abort("Spec directory does not exist: {spec_dir}")
  }

  # Create output directory if needed
  fs::dir_create(output_dir, recurse = TRUE)

  # Get all spec files
  spec_files <- fs::dir_ls(spec_dir, glob = "*.json")

  if (length(spec_files) == 0) {
    cli::cli_warn("No spec files found in {spec_dir}")
    return(data.frame())
  }

  # Initialize results
  all_results <- list()

  # Process each spec
  for (spec_file in spec_files) {
    spec_name <- fs::path_ext_remove(fs::path_file(spec_file))
    spec_name <- sub("\\.v\\d+$", "", spec_name)  # Remove version suffix

    if (verbose) cli::cli_h2("Benchmarking spec: {spec_name}")

    # Load spec
    spec_data <- jsonlite::read_json(spec_file)

    # Benchmark each language
    for (lang in languages) {
      if (verbose) cli::cli_inform("Benchmarking {lang} implementation...")

      bench_result <- tryCatch({
        if (lang == "R") {
          .benchmark_r_function(spec_data, max_time, min_iterations)
        } else if (lang == "python") {
          .benchmark_python_function(spec_data, max_time, min_iterations)
        } else if (lang == "rust") {
          .benchmark_rust_function(spec_data, max_time, min_iterations)
        } else {
          cli::cli_warn("Benchmarking not implemented for language: {lang}")
          NULL
        }
      }, error = function(e) {
        cli::cli_warn("Failed to benchmark {lang} for {spec_name}: {e$message}")
        NULL
      })

      if (!is.null(bench_result)) {
        # Add metadata
        bench_result$spec_id <- spec_name
        bench_result$language <- lang
        bench_result$timestamp <- Sys.time()
        bench_result$hardware_hash <- .get_hardware_hash()

        all_results[[length(all_results) + 1]] <- bench_result
      }
    }
  }

  # Combine results
  if (length(all_results) > 0) {
    results_df <- do.call(rbind, all_results)

    # Save to parquet database
    .save_benchmark_results(results_df, output_dir)

    if (verbose) {
      .print_bench_summary(results_df)
    }

    return(results_df)
  } else {
    return(data.frame())
  }
}

# Benchmark R function
.benchmark_r_function <- function(spec_data, max_time, min_iterations) {
  func_name <- spec_data$function_name

  # Check if function exists
  if (!exists(func_name, mode = "function")) {
    stop("Function {func_name} not found in R environment")
  }

  func <- get(func_name)
  inputs <- spec_data$inputs

  # Convert inputs to R objects
  args <- lapply(inputs, function(x) {
    if (is.list(x) && !is.null(x$`_array`)) {
      x$`_array`
    } else {
      x
    }
  })

  # Run benchmark
  bench_result <- bench::mark(
    do.call(func, args),
    min_iterations = min_iterations,
    max_iterations = NULL,
    min_time = 0.5,
    max_time = max_time,
    check = FALSE,
    memory = TRUE
  )

  # Extract key metrics - bench returns a tibble with list columns
  # Note: bench doesn't provide max, we'll calculate it from time vector
  time_values <- as.numeric(bench_result$time[[1]])

  data.frame(
    min = as.numeric(bench_result$min[1]),
    median = as.numeric(bench_result$median[1]),
    max = max(time_values),
    itr_per_sec = bench_result$`itr/sec`[1],
    n_itr = bench_result$n_itr[1],
    memory = as.numeric(bench_result$mem_alloc[1]),
    stringsAsFactors = FALSE
  )
}

# Benchmark Python function
.benchmark_python_function <- function(spec_data, max_time, min_iterations) {
  # Check for reticulate
  if (!requireNamespace("reticulate", quietly = TRUE)) {
    stop("Package 'reticulate' is required for Python benchmarking")
  }

  func_name <- spec_data$function_name
  module_name <- spec_data$module_name %||% "main"

  # Create Python benchmark script
  py_script <- sprintf('
import json
import time
import gc
from %s import %s

# Load spec
with open("%s") as f:
    spec = json.load(f)

inputs = spec["inputs"]
# Convert array notation
for key, val in inputs.items():
    if isinstance(val, dict) and "_array" in val:
        inputs[key] = val["_array"]

# Warm up
for _ in range(3):
    %s(**inputs)

# Benchmark
times = []
iterations = 0
start_time = time.perf_counter()

while (time.perf_counter() - start_time) < %f and iterations < 1000:
    gc.collect()
    iter_start = time.perf_counter()
    %s(**inputs)
    iter_end = time.perf_counter()
    times.append(iter_end - iter_start)
    iterations += 1
    if iterations >= %d and (time.perf_counter() - start_time) >= 0.5:
        break

# Calculate statistics
import statistics
result = {
    "min": min(times),
    "median": statistics.median(times),
    "max": max(times),
    "n_itr": len(times),
    "itr_per_sec": len(times) / sum(times)
}
print(json.dumps(result))
', module_name, func_name, spec_data$spec_file, func_name, max_time, func_name, min_iterations)

  # Write temporary script
  temp_script <- tempfile(fileext = ".py")
  writeLines(py_script, temp_script)

  # Run benchmark
  result <- system2("python", temp_script, stdout = TRUE, stderr = FALSE)

  # Parse result
  bench_data <- jsonlite::fromJSON(paste(result, collapse = "\n"))

  data.frame(
    min = bench_data$min,
    median = bench_data$median,
    max = bench_data$max,
    itr_per_sec = bench_data$itr_per_sec,
    n_itr = bench_data$n_itr,
    memory = NA_real_,  # Python doesn't easily provide memory stats
    stringsAsFactors = FALSE
  )
}

# Benchmark Rust function using cargo bench
.benchmark_rust_function <- function(spec_data, max_time, min_iterations) {
  # Check if cargo is available
  if (!.has_cargo()) {
    cli::cli_warn("Cargo not found. Skipping Rust benchmarks.")
    return(NULL)
  }

  # Find Rust project root (look for Cargo.toml)
  rust_root <- .find_rust_root()
  if (is.null(rust_root)) {
    cli::cli_warn("No Rust project found (missing Cargo.toml). Skipping Rust benchmarks.")
    return(NULL)
  }

  # Extract function name and module info
  func_name <- spec_data$function_name
  module_name <- spec_data$module %||% "lib"

  # Generate benchmark file
  bench_file <- .generate_rust_benchmark(spec_data, rust_root)

  # Run cargo bench with JSON output
  cli::cli_progress_step("Running cargo bench for {func_name}")

  # Run benchmark and capture JSON output
  bench_result <- tryCatch({
    # Run cargo bench with criterion's JSON output
    # We use --bench flag to run only our generated benchmark
    bench_name <- paste0("bench_", func_name)
    result <- system2(
      "cargo",
      c("bench", "--bench", bench_name, "--", "--output-format", "json"),
      stdout = TRUE,
      stderr = FALSE,
      env = c(Sys.getenv(), "CARGO_TARGET_DIR" = "target_specverse"),
      wd = rust_root
    )

    # Parse criterion JSON output
    .parse_criterion_output(result, func_name)
  }, error = function(e) {
    cli::cli_warn(c(
      "Failed to run Rust benchmark for {func_name}",
      "i" = "Error: {e$message}"
    ))
    NULL
  })

  # Clean up temporary benchmark file if needed
  if (!is.null(bench_file) && fs::file_exists(bench_file)) {
    fs::file_delete(bench_file)
  }

  bench_result
}

# Get hardware hash for consistent comparisons
.get_hardware_hash <- function() {
  info <- Sys.info()
  # Create a simple hash from system info
  hardware_string <- paste(
    info["sysname"],
    info["machine"],
    info["nodename"],
    sep = "_"
  )
  digest::digest(hardware_string, algo = "xxhash32")
}

