# Benchmark Python function
.benchmark_python_function <- function(spec_data, max_time, min_iterations) {
  # Check for reticulate
  if (!requireNamespace("reticulate", quietly = TRUE)) {
    stop("Package 'reticulate' is required for Python benchmarking")
  }

  func_name <- spec_data$function_name
  module_name <- spec_data$module_name %||% "main"

  # Create Python benchmark script
  py_script <- sprintf('
import json
import time
import gc
from %s import %s

# Load spec
with open("%s") as f:
    spec = json.load(f)

inputs = spec["inputs"]
# Convert array notation
for key, val in inputs.items():
    if isinstance(val, dict) and "_array" in val:
        inputs[key] = val["_array"]

# Warm up
for _ in range(3):
    %s(**inputs)

# Benchmark
times = []
iterations = 0
start_time = time.perf_counter()

while (time.perf_counter() - start_time) < %f and iterations < 1000:
    gc.collect()
    iter_start = time.perf_counter()
    %s(**inputs)
    iter_end = time.perf_counter()
    times.append(iter_end - iter_start)
    iterations += 1
    if iterations >= %d and (time.perf_counter() - start_time) >= 0.5:
        break

# Calculate statistics
import statistics
result = {
    "min": min(times),
    "median": statistics.median(times),
    "max": max(times),
    "n_itr": len(times),
    "itr_per_sec": len(times) / sum(times)
}
print(json.dumps(result))
', module_name, func_name, spec_data$spec_file, func_name, max_time, func_name, min_iterations)

  # Write temporary script
  temp_script <- tempfile(fileext = ".py")
  writeLines(py_script, temp_script)

  # Run benchmark
  result <- system2("python", temp_script, stdout = TRUE, stderr = FALSE)

  # Parse result
  bench_data <- jsonlite::fromJSON(paste(result, collapse = "\n"))

  data.frame(
    min = bench_data$min,
    median = bench_data$median,
    max = bench_data$max,
    itr_per_sec = bench_data$itr_per_sec,
    n_itr = bench_data$n_itr,
    memory = NA_real_,  # Python doesn't easily provide memory stats
    stringsAsFactors = FALSE
  )
}

# Benchmark Rust function using cargo bench
.benchmark_rust_function <- function(spec_data, max_time, min_iterations) {
  # Check if cargo is available
  if (!.has_cargo()) {
    cli::cli_warn("Cargo not found. Skipping Rust benchmarks.")
    return(NULL)
  }

  # Find Rust project root (look for Cargo.toml)
  rust_root <- .find_rust_root()
  if (is.null(rust_root)) {
    cli::cli_warn("No Rust project found (missing Cargo.toml). Skipping Rust benchmarks.")
    return(NULL)
  }

  # Extract function name and module info
  func_name <- spec_data$function_name
  module_name <- spec_data$module %||% "lib"

  # Generate benchmark file
  bench_file <- .generate_rust_benchmark(spec_data, rust_root)

  # Run cargo bench with JSON output
  cli::cli_progress_step("Running cargo bench for {func_name}")

  # Run benchmark and capture JSON output
  bench_result <- tryCatch({
    # Run cargo bench with criterion's JSON output
    # We use --bench flag to run only our generated benchmark
    bench_name <- paste0("bench_", func_name)
    result <- system2(
      "cargo",
      c("bench", "--bench", bench_name, "--", "--output-format", "json"),
      stdout = TRUE,
      stderr = FALSE,
      env = c(Sys.getenv(), "CARGO_TARGET_DIR" = "target_specverse"),
      wd = rust_root
    )

    # Parse criterion JSON output
    .parse_criterion_output(result, func_name)
  }, error = function(e) {
    cli::cli_warn(c(
      "Failed to run Rust benchmark for {func_name}",
      "i" = "Error: {e$message}"
    ))
    NULL
  })

  # Clean up temporary benchmark file if needed
  if (!is.null(bench_file) && fs::file_exists(bench_file)) {
    fs::file_delete(bench_file)
  }

  bench_result
}

# Get hardware hash for consistent comparisons
.get_hardware_hash <- function() {
  info <- Sys.info()
  # Create a simple hash from system info
  hardware_string <- paste(
    info["sysname"],
    info["machine"],
    info["nodename"],
    sep = "_"
  )
  digest::digest(hardware_string, algo = "xxhash32")
}

# Check if cargo is available
.has_cargo <- function() {
  Sys.which("cargo") != ""
}

# Find Rust project root by looking for Cargo.toml
.find_rust_root <- function() {
  # Start from current directory and walk up
  current_dir <- getwd()

  while (TRUE) {
    cargo_path <- fs::path(current_dir, "Cargo.toml")
    if (fs::file_exists(cargo_path)) {
      return(current_dir)
    }

    parent <- fs::path_dir(current_dir)
    if (parent == current_dir) {
      # Reached root without finding Cargo.toml
      return(NULL)
    }
    current_dir <- parent
  }
}

# Generate Rust benchmark file
.generate_rust_benchmark <- function(spec_data, rust_root) {
  func_name <- spec_data$function_name
  module_name <- spec_data$module %||% "lib"

  # Create benches directory if it doesn't exist
  benches_dir <- fs::path(rust_root, "benches")
  fs::dir_create(benches_dir, recurse = TRUE)

  # Generate benchmark filename
  bench_file <- fs::path(benches_dir, paste0("bench_", func_name, ".rs"))

  # Convert inputs to Rust literals
  rust_inputs <- .convert_to_rust_literals(spec_data$inputs)

  # Generate benchmark code
  bench_code <- sprintf('
use criterion::{black_box, criterion_group, criterion_main, Criterion};
use %s::%s;

fn benchmark_%s(c: &mut Criterion) {
    c.bench_function("%s", |b| {
        b.iter(|| {
            %s(
                %s
            )
        })
    });
}

criterion_group!(benches, benchmark_%s);
criterion_main!(benches);
',
    module_name,
    func_name,
    func_name,
    func_name,
    func_name,
    paste0("black_box(", rust_inputs, ")", collapse = ",\n                "),
    func_name
  )

  # Write benchmark file
  writeLines(bench_code, bench_file)

  # Also ensure Cargo.toml has criterion dependency
  .ensure_criterion_dependency(rust_root)

  bench_file
}

# Convert R/JSON values to Rust literals
.convert_to_rust_literals <- function(inputs) {
  rust_values <- character()

  for (name in names(inputs)) {
    val <- inputs[[name]]

    # Handle array notation
    if (is.list(val) && "_array" %in% names(val)) {
      val <- val[["_array"]]
    }

    # Convert to Rust literal based on type
    if (is.numeric(val)) {
      if (length(val) == 1) {
        rust_val <- as.character(val)
        # Add type suffix if it's a float
        if (grepl("\\.", rust_val)) {
          rust_val <- paste0(rust_val, "f64")
        }
      } else {
        # Vector -> array or vec!
        rust_val <- sprintf("vec![%s]", 
                          paste(val, collapse = ", "))
      }
    } else if (is.character(val)) {
      if (length(val) == 1) {
        rust_val <- sprintf('"%s"', val)
      } else {
        rust_val <- sprintf('vec![%s]', 
                          paste(sprintf('"%s"', val), collapse = ", "))
      }
    } else if (is.logical(val)) {
      rust_val <- tolower(as.character(val))
    } else {
      cli::cli_warn("Unsupported type for Rust conversion: {class(val)}")
      rust_val <- "todo!()"
    }

    rust_values <- c(rust_values, rust_val)
  }

  rust_values
}

# Parse criterion JSON output
.parse_criterion_output <- function(output_lines, func_name) {
  # Criterion outputs JSON lines when using --output-format json
  # We need to find the line with our benchmark results

  json_lines <- output_lines[grepl("^\\{", output_lines)]

  if (length(json_lines) == 0) {
    cli::cli_warn("No JSON output found from criterion")
    return(NULL)
  }

  # Look for the benchmark result line
  for (line in json_lines) {
    tryCatch({
      data <- jsonlite::fromJSON(line, simplifyVector = FALSE)

      # Check if this is a benchmark complete event
      if (!is.null(data$reason) && data$reason == "benchmark-complete") {
        # Extract timing data (criterion reports in nanoseconds)
        typical <- data$typical

        if (!is.null(typical)) {
          # Convert nanoseconds to seconds
          ns_to_sec <- 1e-9

          return(data.frame(
            min = (typical$lower_bound %||% typical$estimate) * ns_to_sec,
            median = typical$estimate * ns_to_sec,
            max = (typical$upper_bound %||% typical$estimate) * ns_to_sec,
            itr_per_sec = 1 / (typical$estimate * ns_to_sec),
            n_itr = data$sample_count %||% 100,
            memory = NA_real_,
            stringsAsFactors = FALSE
          ))
        }
      }
    }, error = function(e) {
      # Skip malformed JSON lines
      NULL
    })
  }

  cli::cli_warn("Could not parse criterion output for {func_name}")
  NULL
}

# Ensure Cargo.toml has criterion dependency
.ensure_criterion_dependency <- function(rust_root) {
  cargo_toml <- fs::path(rust_root, "Cargo.toml")

  if (!fs::file_exists(cargo_toml)) {
    return()
  }

  # Read Cargo.toml
  cargo_content <- readLines(cargo_toml)

  # Check if criterion is already present
  if (any(grepl("criterion\\s*=", cargo_content))) {
    return()
  }

  # Find [dev-dependencies] section
  dev_deps_line <- which(grepl("^\\[dev-dependencies\\]", cargo_content))

  if (length(dev_deps_line) == 0) {
    # Add dev-dependencies section at the end
    cargo_content <- c(
      cargo_content,
      "",
      "[dev-dependencies]",
      'criterion = "0.5"'
    )
  } else {
    # Insert criterion after [dev-dependencies]
    cargo_content <- append(
      cargo_content,
      'criterion = "0.5"',
      after = dev_deps_line[1]
    )
  }

  # Write back
  writeLines(cargo_content, cargo_toml)

  cli::cli_alert_info("Added criterion to Cargo.toml dev-dependencies")
}

