#' Run Performance Benchmarks
#'
#' Executes performance benchmarks for functions defined in spec files and
#' stores results in a parquet database for tracking performance over time.
#'
#' @param spec_dir Directory containing spec files (default: "spec")
#' @param output_dir Directory for performance database (default: "results")
#' @param languages Character vector of languages to benchmark (default: c("R", "python", "rust"))
#' @param max_time Maximum time in seconds for each benchmark (default: 5)
#' @param min_iterations Minimum iterations for reliable benchmarks (default: 3)
#' @param verbose Logical, whether to print progress messages
#'
#' @return A data frame with benchmark results
#' @export
#'
#' @examples
#' \dontrun{
#' # Run benchmarks for all specs
#' results <- sv_bench()
#' 
#' # Run benchmarks with custom settings
#' results <- sv_bench(languages = c("R", "python", "rust"), max_time = 10)
#' }
sv_bench <- function(spec_dir = "spec", 
                     output_dir = "results",
                     languages = c("R", "python"),
                     max_time = 5,
                     min_iterations = 3,
                     verbose = TRUE) {

  # Check for bench package
  if (!requireNamespace("bench", quietly = TRUE)) {
    cli::cli_abort(
      c("Package {.pkg bench} is required for benchmarking",
        "i" = "Install it with: install.packages('bench')")
    )
  }

  # Validate directories
  if (!fs::dir_exists(spec_dir)) {
    cli::cli_abort("Spec directory does not exist: {spec_dir}")
  }

  # Create output directory if needed
  fs::dir_create(output_dir, recurse = TRUE)

  # Get all spec files
  spec_files <- fs::dir_ls(spec_dir, glob = "*.json")

  if (length(spec_files) == 0) {
    cli::cli_warn("No spec files found in {spec_dir}")
    return(data.frame())
  }

  # Initialize results
  all_results <- list()

  # Process each spec
  for (spec_file in spec_files) {
    spec_name <- fs::path_ext_remove(fs::path_file(spec_file))
    spec_name <- sub("\\.v\\d+$", "", spec_name)  # Remove version suffix

    if (verbose) cli::cli_h2("Benchmarking spec: {spec_name}")

    # Load spec
    spec_data <- jsonlite::read_json(spec_file)

    # Benchmark each language
    for (lang in languages) {
      if (verbose) cli::cli_inform("Benchmarking {lang} implementation...")

      bench_result <- tryCatch({
        if (lang == "R") {
          .benchmark_r_function(spec_data, max_time, min_iterations)
        } else if (lang == "python") {
          .benchmark_python_function(spec_data, max_time, min_iterations)
        } else if (lang == "rust") {
          .benchmark_rust_function(spec_data, max_time, min_iterations)
        } else {
          cli::cli_warn("Benchmarking not implemented for language: {lang}")
          NULL
        }
      }, error = function(e) {
        cli::cli_warn("Failed to benchmark {lang} for {spec_name}: {e$message}")
        NULL
      })

      if (!is.null(bench_result)) {
        # Add metadata
        bench_result$spec_id <- spec_name
        bench_result$language <- lang
        bench_result$timestamp <- Sys.time()
        bench_result$hardware_hash <- .get_hardware_hash()

        all_results[[length(all_results) + 1]] <- bench_result
      }
    }
  }

  # Combine results
  if (length(all_results) > 0) {
    results_df <- do.call(rbind, all_results)

    # Save to parquet database
    .save_benchmark_results(results_df, output_dir)

    if (verbose) {
      .print_bench_summary(results_df)
    }

    return(results_df)
  } else {
    return(data.frame())
  }
}

#' Import Cargo Bench Results
#'
#' Imports existing cargo bench results from Criterion's output directory
#' into the specverse performance database. This is useful for integrating
#' benchmarks that were run outside of sv_bench().
#'
#' @param rust_root Path to Rust project root (containing Cargo.toml)
#' @param spec_names Character vector of spec names to import (optional)
#' @param output_dir Directory for performance database (default: "results")
#' @param verbose Logical, whether to print progress messages
#'
#' @return A data frame with imported benchmark results
#' @export
#'
#' @examples
#' \dontrun{
#' # Import all available cargo bench results
#' results <- sv_import_cargo_bench("path/to/rust/project")
#' 
#' # Import specific benchmarks only
#' results <- sv_import_cargo_bench(
#'   "path/to/rust/project",
#'   spec_names = c("my_function", "other_function")
#' )
#' }
sv_import_cargo_bench <- function(rust_root = ".", 
                                 spec_names = NULL,
                                 output_dir = "results",
                                 verbose = TRUE) {
  # Validate inputs
  if (!fs::dir_exists(rust_root)) {
    cli::cli_abort("Rust project root does not exist: {rust_root}")
  }

  cargo_toml <- fs::path(rust_root, "Cargo.toml")
  if (!fs::file_exists(cargo_toml)) {
    cli::cli_abort("No Cargo.toml found in: {rust_root}")
  }

  # Find criterion output directory
  criterion_dir <- fs::path(rust_root, "target", "criterion")
  if (!fs::dir_exists(criterion_dir)) {
    cli::cli_warn("No criterion output directory found at: {criterion_dir}")
    cli::cli_alert_info("Run 'cargo bench' first to generate benchmark results")
    return(data.frame())
  }

  # Get all benchmark directories
  bench_dirs <- fs::dir_ls(criterion_dir, type = "directory")

  if (length(bench_dirs) == 0) {
    cli::cli_warn("No benchmark results found in criterion directory")
    return(data.frame())
  }

  # Filter by spec names if provided
  if (!is.null(spec_names)) {
    bench_dirs <- bench_dirs[basename(bench_dirs) %in% spec_names]
  }

  if (verbose) {
    cli::cli_alert_info("Found {length(bench_dirs)} benchmark(s) to import")
  }

  # Import each benchmark
  all_results <- list()

  for (bench_dir in bench_dirs) {
    bench_name <- basename(bench_dir)

    # Look for estimates.json file
    estimates_file <- fs::path(bench_dir, "base", "estimates.json")

    if (!fs::file_exists(estimates_file)) {
      if (verbose) {
        cli::cli_warn("No estimates.json found for {bench_name}")
      }
      next
    }

    # Parse estimates
    tryCatch({
      estimates <- jsonlite::read_json(estimates_file)

      # Extract timing data (criterion stores in nanoseconds)
      ns_to_sec <- 1e-9

      result <- data.frame(
        spec_id = bench_name,
        language = "rust",
        timestamp = fs::file_info(estimates_file)$modification_time,
        min = (estimates$mean$confidence_interval$lower_bound %||% 
               estimates$mean$point_estimate) * ns_to_sec,
        median = estimates$mean$point_estimate * ns_to_sec,
        max = (estimates$mean$confidence_interval$upper_bound %||% 
               estimates$mean$point_estimate) * ns_to_sec,
        itr_per_sec = 1 / (estimates$mean$point_estimate * ns_to_sec),
        n_itr = estimates$sample_count %||% 100,
        memory = NA_real_,
        hardware_hash = .get_hardware_hash(),
        stringsAsFactors = FALSE
      )

      all_results[[length(all_results) + 1]] <- result

      if (verbose) {
        cli::cli_alert_success("Imported {bench_name}")
      }

    }, error = function(e) {
      cli::cli_warn(c(
        "Failed to parse estimates for {bench_name}",
        "i" = "Error: {e$message}"
      ))
    })
  }

  # Combine and save results
  if (length(all_results) > 0) {
    results_df <- do.call(rbind, all_results)

    # Save to parquet database
    .save_benchmark_results(results_df, output_dir)

    if (verbose) {
      cli::cli_alert_success("Imported {nrow(results_df)} benchmark result(s)")
      .print_bench_summary(results_df)
    }

    return(results_df)
  } else {
    return(data.frame())
  }
}

